// ── Normalize HTML to plain text ──
const html = $input.first().json.data || $input.first().json.body || '';

// Check for HTTP failure from previous node
if ($input.first().json.error) {
  return [{ json: {
    error: true,
    errorMessage: $input.first().json.error.message || 'HTTP request failed',
    tracked_page_id: $('Loop Over Pages').first().json.id,
    company_name: $('Loop Over Pages').first().json.company_name
  }}];
}

// Strip script, style, nav, footer, header, cookie-banner tags and their content
let text = html
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<div[^>]*(?:cookie|consent|banner)[^>]*>[\s\S]*?<\/div>/gi, '');

// Strip remaining HTML tags
text = text.replace(/<[^>]+>/g, ' ');

// Decode common HTML entities
text = text
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/&quot;/g, '"')
  .replace(/&#39;/g, "'")
  .replace(/&nbsp;/g, ' ');

// Collapse whitespace
text = text.replace(/\s+/g, ' ').trim();

// Compute content hash (FNV-1a 64-bit, no require needed)
function fnv1a64(str) {
  let h1 = 0x811c9dc5 >>> 0;
  let h2 = 0xcbf29ce4 >>> 0;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 0x01000193) >>> 0;
    h2 = Math.imul(h2 ^ (c >> 8 | c), 0x01000193) >>> 0;
  }
  return h2.toString(16).padStart(8, '0') + h1.toString(16).padStart(8, '0');
}
const contentHash = fnv1a64(text);

// Compute week_start_date (Monday of current ISO week, UTC)
const now = new Date();
const day = now.getUTCDay(); // 0=Sun
const diff = day === 0 ? 6 : day - 1;
const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
const weekStartDate = monday.toISOString().slice(0, 10);

const page = $('Loop Over Pages').first().json;

return [{ json: {
  error: false,
  tracked_page_id: page.id,
  company_name: page.company_name,
  company_slug: page.company_slug,
  url: page.url,
  url_type: page.url_type,
  week_start_date: weekStartDate,
  text_content: text,
  content_hash: contentHash,
  http_status: $input.first().json.statusCode || 200
}}];

// ── Helpers ──
function truncateText(text, maxLen) {
  if (!text) return '';
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen) + '\n[...truncated]';
}

function computeSimpleDiff(oldText, newText) {
  if (!oldText || !newText) return 'No previous text available for comparison.';
  const oldSentences = new Set(oldText.split(/(?<=[.!?])\s+/).filter(s => s.length > 10));
  const newSentences = new Set(newText.split(/(?<=[.!?])\s+/).filter(s => s.length > 10));
  const added = [...newSentences].filter(s => !oldSentences.has(s));
  const removed = [...oldSentences].filter(s => !newSentences.has(s));
  let summary = '';
  if (added.length > 0) {
    summary += 'ADDED (' + added.length + ' sentences):\n' + added.slice(0, 15).map(s => '+ ' + s.slice(0, 200)).join('\n') + '\n';
  }
  if (removed.length > 0) {
    summary += 'REMOVED (' + removed.length + ' sentences):\n' + removed.slice(0, 15).map(s => '- ' + s.slice(0, 200)).join('\n') + '\n';
  }
  if (!summary) summary = 'Minor wording changes detected (no full sentences added or removed).';
  return summary;
}

// ── Main ──
const current = $('Postgres: Upsert Snapshot').first().json;
const prevRows = $('Postgres: Get Previous Snapshot').all();
const pageData = $('Normalize HTML & Hash').first().json;

if (!prevRows.length || prevRows[0].json.content_hash === undefined) {
  return [{ json: { changed: false, reason: 'no_previous_snapshot' } }];
}

const prev = prevRows[0].json;

if (prev.content_hash === current.content_hash) {
  return [{ json: { changed: false, reason: 'hash_unchanged' } }];
}

// Truncate texts to ~3K tokens each for LLM efficiency
const MAX_TEXT_LEN = 12000;
const oldTextTruncated = truncateText(prev.text_content, MAX_TEXT_LEN);
const newTextTruncated = truncateText(current.text_content, MAX_TEXT_LEN);
const diffSummaryText = computeSimpleDiff(prev.text_content, current.text_content);

return [{ json: {
  changed: true,
  tracked_page_id: current.tracked_page_id,
  week_start_date: current.week_start_date,
  new_snapshot_id: current.id,
  old_snapshot_id: prev.id,
  new_hash: current.content_hash,
  old_hash: prev.content_hash,
  company_name: pageData.company_name,
  company_slug: pageData.company_slug,
  url: pageData.url,
  url_type: pageData.url_type,
  old_text_truncated: oldTextTruncated,
  new_text_truncated: newTextTruncated,
  diff_summary_text: diffSummaryText
}}];

