const VALID_TAGS = new Set([
  'ICP_SHIFT','VALUE_PROP_CHANGE','CATEGORY_POSITIONING','PROOF_POINTS',
  'FEATURE_PROMINENCE','PRICING_PACKAGING','TRUST_RISK','AI_REFRAMING',
  'CTA_CHANGE','DESIGN_STRUCTURE','NOISE'
]);

const diffData = $('If Hash Changed').first().json;
let classification;

try {
  const raw = $input.first().json;
  const content = raw.content?.[0]?.text || raw.choices?.[0]?.message?.content || '{}';
  classification = JSON.parse(content);
} catch (e) {
  classification = {
    primary_tag: 'NOISE',
    secondary_tags: [],
    rationale: 'LLM response could not be parsed',
    implication: 'Unknown',
    confidence: 0,
    change_magnitude: 'minor'
  };
}

// Validate primary_tag
if (!VALID_TAGS.has(classification.primary_tag)) {
  classification.primary_tag = 'NOISE';
}

// Validate secondary_tags
if (Array.isArray(classification.secondary_tags)) {
  classification.secondary_tags = classification.secondary_tags.filter(t => VALID_TAGS.has(t));
} else {
  classification.secondary_tags = [];
}

// Validate change_magnitude
const validMagnitudes = new Set(['minor','moderate','major']);
if (!validMagnitudes.has(classification.change_magnitude)) {
  classification.change_magnitude = 'minor';
}

// Build diff_summary with actual rationale
const diffSummary = `${classification.primary_tag} (${classification.change_magnitude}): ${classification.rationale || 'No rationale provided'}`;

return [{ json: {
  ...diffData,
  diff_summary: diffSummary,
  change_magnitude: classification.change_magnitude,
  primary_tag: classification.primary_tag,
  secondary_tags: classification.secondary_tags,
  rationale: classification.rationale,
  implication: classification.implication,
  confidence: classification.confidence
}}];

// Collect failure from errored fetch
const page = $('Loop Over Pages').first().json;
const errorMsg = $json.errorMessage || 'Unknown fetch error';

// Compute week_start_date (Monday of current ISO week, UTC)
const now = new Date();
const day = now.getUTCDay(); // 0=Sun
const diff = day === 0 ? 6 : day - 1;
const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
const weekStartDate = monday.toISOString().slice(0, 10);

return [{ json: {
  failure: true,
  tracked_page_id: page.id,
  company_name: page.company_name,
  url: page.url,
  error: errorMsg,
  week_start_date: weekStartDate
}}];

// Map change_magnitude to severity and prepare signal data
const diffData = $('Validate & Build Diff').first().json;
const classificationId = $('Postgres: Insert Classification').first().json.id;
const diffId = $('Postgres: Insert Diff').first().json.id;

// Skip NOISE signals
if (diffData.primary_tag === 'NOISE') {
  return [{ json: { skip: true, reason: 'NOISE tag' } }];
}

// Map change_magnitude to severity
let severity = 2; // default: Low
if (diffData.change_magnitude === 'major') severity = 4; // High
else if (diffData.change_magnitude === 'moderate') severity = 3; // Medium

// Build title and summary
const title = `${diffData.company_name}: ${diffData.primary_tag.replace(/_/g, ' ')} (${diffData.change_magnitude})`;
const summary = `${diffData.rationale} Implication: ${diffData.implication}`;

// Evidence URL is the tracked page URL
const evidenceUrls = [diffData.url];

return [{ json: {
  skip: false,
  signal_type: 'messaging',
  severity: severity,
  confidence: diffData.confidence,
  title: title,
  summary: summary,
  evidence_urls: evidenceUrls,
  source_schema: 'public',
  source_table: 'classified_changes',
  source_id: diffId,
  meta: {
    company_name: diffData.company_name,
    company_slug: diffData.company_slug,
    url_type: diffData.url_type,
    primary_tag: diffData.primary_tag,
    secondary_tags: diffData.secondary_tags,
    change_magnitude: diffData.change_magnitude,
    week_start_date: diffData.week_start_date
  }
}}];
